module ButtonCounter #(
  parameter COUNT_RISING_EDGE = 0
)(

  //////////// CLOCK //////////
  input wire                   clk,
  input wire                   resetn,

  //////////// SEG7 //////////
  output wire [7:0]            hex0,
  output wire [7:0]            hex1,
  output wire [7:0]            hex2,
  output wire [7:0]            hex3,
  output wire [7:0]            hex4,
  output wire [7:0]            hex5,

  //////////// KEY //////////
  input  wire [1:0]            key
);

localparam NUMBER_HEX_ELEMENTS = 6;
localparam COUNTER_SIZE        = 20;

localparam MAX_PER_ELEMENT = 9;
// localparam MAX_VALUE       = 999999; //figure out how to calculate this
logic [31:0] max_val; //figured out a way

always_comb begin
  max_val = 0;
  for (integer w=0; w< NUMBER_HEX_ELEMENTS; w=w+1) begin
    max_val = max_val + (MAX_PER_ELEMENT * 10**w);
  end
end


typedef enum logic [7:0] {
  ZERO  = 8'b11000000,
  ONE   = 8'b11111001,
  TWO   = 8'b10100100,
  THREE = 8'b10110000,
  FOUR  = 8'b10011001,
  FIVE  = 8'b10010010,
  SIX   = 8'b10000010,
  SEVEN = 8'b11111000,
  EIGHT = 8'b10000000,
  NINE  = 8'b10011000
} seg4num_e;

typedef enum logic {
  IDLE          = 1'h0,
  WAIT_FOR_CONV = 1'h1
} sys_state_e;

sys_state_e sys_state, sys_state_nxt;

logic count_up, count_up_q;
logic count_down, count_down_q;




logic [COUNTER_SIZE-1:0] counter, counter_nxt, counter_q;
logic  convdone, convdone_q;


seg4num_e num [NUMBER_HEX_ELEMENTS-1:0];
logic [23:0] number, number_q;

always_ff @(posedge clk or negedge resetn) begin
  if(!resetn) begin
    number_q   <= 23'h0;
    convdone_q <= 1'b0;
  end else begin
    if (convdone) begin
      number_q   <= number;
      convdone_q <=  convdone;
    end

  end
end


assign hex0 = num[0];
assign hex1 = num[1];
assign hex2 = num[2];
assign hex3 = num[3];
assign hex4 = num[4];
assign hex5 = num[5];


//999999 is 20 bits

logic [3:0] seg [0:5];

logic startConv;

metastability_register_N #(
  .BUSWIDTH (1)
) metastab1 (
  .clk      (clk      ),
  .busIn    (key[0]   ),
  .busOut   (count_up )
);



metastability_register_N #(
  .BUSWIDTH (1)
) metastab2 (
  .clk      (clk        ),
  .busIn    (key[1]     ),
  .busOut   (count_down )
);

Binary_to_BCD
#(
  .INPUT_WIDTH    (COUNTER_SIZE),
  .DECIMAL_DIGITS (NUMBER_HEX_ELEMENTS)
) BCD (
  .i_Clock        (clk),
  .i_Binary       (counter),
  .i_Start        (startConv),
  //
  .o_BCD          (number),
  .o_DV           (convdone)
);

//=======================================================
//  Structural coding
//=======================================================

assign count_up_re   = count_up & !count_up_q;
assign count_down_re = count_down & !count_down_q;

for (genvar h=0; h<NUMBER_HEX_ELEMENTS; h=h+1) begin
  assign seg[h] = number_q[h*3+: 3];
end

always @(*) begin
    startConv = 1'b0;
    case(sys_state)
      IDLE : begin
        if(counter_q != counter)
        begin
          sys_state_nxt = WAIT_FOR_CONV;
          startConv = 1'b1;
        end
      end

      WAIT_FOR_CONV : begin
        startConv = 1'b0;
        if(convdone)
          sys_state_nxt = IDLE;
      end

    endcase
end

always_ff @(posedge clk or negedge resetn) begin
  if (!resetn) begin
    sys_state_nxt <= IDLE;
    counter       <= {COUNTER_SIZE{1'b0}};
    counter_q     <= {COUNTER_SIZE{1'b0}};
    count_up_q    <= 1'b0;
    count_down_q  <= 1'b0;
  end else begin
    sys_state     <= sys_state_nxt;
    counter       <= counter_nxt;
    count_up_q    <= count_up;
    count_down_q  <= count_down;
    if (sys_state == IDLE) begin
      counter_q     <= counter;
    end
  end
end



logic [1:0] buttons;
assign buttons = COUNT_RISING_EDGE ? {count_up_re, count_down_re} :
                                     {count_up, count_down};


always_comb begin
  case(buttons)
    2'b00, 2'b11: begin
      counter_nxt = counter;
    end

    2'b01: begin
      counter_nxt = (counter > 0) ? counter - 1'b1 :
                                    counter;
    end

    2'b10: begin
      counter_nxt = (counter < max_val) ? counter + 1'b1 :
                                            counter;
    end

    default: counter_nxt = {COUNTER_SIZE{1'bx}};

  endcase
end


always_ff @(posedge clk or negedge resetn) begin
  if (!resetn) begin
    for (integer i = 0; i < NUMBER_HEX_ELEMENTS; i = i + 1)begin
      num[i] <= 8'hff;
    end
  end else begin
    for (integer n = 0; n < NUMBER_HEX_ELEMENTS; n = n + 1) begin
      case(seg[n])
        0 : num[n] <= ZERO;
        1 : num[n] <= ONE;
        2 : num[n] <= TWO;
        3 : num[n] <= THREE;
        4 : num[n] <= FOUR;
        5 : num[n] <= FIVE;
        6 : num[n] <= SIX;
        7 : num[n] <= SEVEN;
        8 : num[n] <= EIGHT;
        9 : num[n] <= NINE;
        default : num[n] <= 8'hx;
      endcase
    end
  end
end


endmodule

